// index.js

import React, { useState } from 'react';
import ReactDOM from 'react-dom';

const App = () => {
  const [accessToken, setAccessToken] = useState(localStorage.getItem('access_token') || null);

  const login = async () => {
    const clientId = 'YOUR_CLIENT_ID';
    const redirectUri = encodeURIComponent('http://localhost:3000/callback');
    const authUrl = `https://example.com/oauth/authorize?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=read`;

    window.location.href = authUrl;
  };

  const handleCallback = async (url) => {
    const urlParams = new URLSearchParams(new URL(url).search);
    const code = urlParams.get('code');
    if (code) {
      await exchangeCodeForToken(code);
      setAccessToken(localStorage.getItem('access_token'));
      window.history.pushState({}, document.title, "/");
    }
  };

  const exchangeCodeForToken = async (code) => {
    const clientId = 'YOUR_CLIENT_ID';
    const clientSecret = 'YOUR_CLIENT_SECRET';
    const tokenUrl = 'https://example.com/oauth/token';

    try {
      const response = await fetch(tokenUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: encodeURIComponent('http://localhost:3000/callback'),
          client_id: clientId,
          client_secret: clientSecret
        })
      });

      const data = await response.json();
      localStorage.setItem('access_token', data.access_token);
    } catch (error) {
      console.error('Error exchanging code for token:', error);
    }
  };

  const logout = () => {
    localStorage.removeItem('access_token');
    setAccessToken(null);
  };

  React.useEffect(() => {
    handleCallback(window.location.href);
  }, []);

  return (
    <div>
      {accessToken ? (
        <>
          <p>Welcome!</p>
          <button onClick={logout}>Logout</button>
        </>
      ) : (
        <button onClick={login}>Login with OAuth</button>
      )}
    </div>
  );
};

ReactDOM.render(<App />, document.getElementById('root'));